function getGroup(id: StateId): 'active' | 'expansion' | 'big4' {
  if (ACTIVE_PACKAGE.has(id)) return 'active'
  if (EXPANSION_FUTURE.has(id)) return 'expansion'
  return 'big4'
}

const COLOR = {
  active:    { fill: '#C4AA88', opacity: 0.85 },
  expansion: { fill: '#BFC3C7', opacity: 0.55 },
  big4:      { fill: '#3D4045', opacity: 0.72 },
}

const HOVER_OPACITY = {
  active:    1,
  expansion: 0.80,
  big4:      0.90,
}

interface Tooltip {
  id: StateId
  name: string
  group: 'active' | 'expansion' | 'big4'
  x: number
  y: number
}

const GROUP_LABEL = {
  active:    'Pacote Ativo',
  expansion: 'Expansão Futura',
  big4:      'Big 4',
}

export function MapaBrasil() {
  const [tooltip, setTooltip] = useState<Tooltip | null>(null)

  function handleMouseEnter(e: React.MouseEvent<SVGPathElement>, id: StateId) {
    const svg = e.currentTarget.closest('svg') as SVGSVGElement
    const rect = svg.getBoundingClientRect()
    setTooltip({
      id,
      name: STATE_DATA[id].name,
      group: getGroup(id),
      x: e.clientX - rect.left,
      y: e.clientY - rect.top,
    })
  }

  function handleMouseMove(e: React.MouseEvent<SVGPathElement>) {
    if (!tooltip) return
    const svg = e.currentTarget.closest('svg') as SVGSVGElement
    const rect = svg.getBoundingClientRect()
    setTooltip(prev => prev ? { ...prev, x: e.clientX - rect.left, y: e.clientY - rect.top } : null)
  }

  return (
    <div style={{ position: 'relative', width: '100%' }}>
      <svg
        viewBox="0 0 1000 912"
        xmlns="http://www.w3.org/2000/svg"
        style={{ width: '100%', height: 'auto', display: 'block' }}
        aria-label="Mapa do Brasil — estados por grupo de cobertura Bicofino"
        role="img"
        onMouseLeave={() => setTooltip(null)}
      >
        {Object.entries(STATE_DATA).map(([id, state]) => {
          const group = getGroup(id as StateId)
          const color = COLOR[group]
          const isHovered = tooltip?.id === id
          return (
            <path
              key={id}
              id={id}
              d={state.d}
              fill={color.fill}
              stroke="#f2f8ff"
              strokeWidth={0.4}
              opacity={isHovered ? HOVER_OPACITY[group] : color.opacity}
              style={{ transition: 'opacity 180ms ease-out', cursor: 'default' }}
              aria-label={`${state.name} — ${GROUP_LABEL[group]}`}
              onMouseEnter={e => handleMouseEnter(e, id as StateId)}
              onMouseMove={handleMouseMove}
              onMouseLeave={() => setTooltip(null)}
            />
          )
        })}
      </svg>

      {tooltip && (
        <div
          style={{
            position: 'absolute',
            left: tooltip.x + 14,
            top: tooltip.y - 10,
            pointerEvents: 'none',
            background: 'var(--bf-surface, #ffffff)',
            border: '1px solid var(--bf-border-strong, rgba(42,44,43,0.16))',
            padding: '6px 10px',
            display: 'flex',
            flexDirection: 'column',
            gap: 2,
            zIndex: 10,
            minWidth: 120,
          }}
        >
          <span style={{ fontSize: 11, fontWeight: 600, color: 'var(--bf-text-primary, #2a2c2b)', letterSpacing: '0.02em' }}>
            {tooltip.name}
          </span>
          <span style={{ fontSize: 9, fontWeight: 500, color: 'var(--bf-text-secondary, #6d7886)', letterSpacing: '0.08em', textTransform: 'uppercase' }}>
            {GROUP_LABEL[tooltip.group]}
          </span>
        </div>
      )}
    </div>
  )
}
